256 /// Return true if it is desirable to convert an integer computation from a
257 /// given bit width to a new bit width.
258 /// We don't want to convert from a legal or desirable type (like i8) to an
259 /// illegal type or from a smaller to a larger illegal type. A width of '1'
260 /// is always treated as a desirable type because i1 is a fundamental type in
261 /// IR, and there are many specialized optimizations for i1 types.
262 /// Common/desirable widths are equally treated as legal to convert to, in
263 /// order to open up more combining opportunities.
264 bool InstCombinerImpl::shouldChangeType(unsigned FromWidth,
265                                         unsigned ToWidth) const {
266   bool FromLegal = FromWidth == 1 || DL.isLegalInteger(FromWidth);
267   bool ToLegal = ToWidth == 1 || DL.isLegalInteger(ToWidth);
268 
269   // Convert to desirable widths even if they are not legal types.
270   // Only shrink types, to prevent infinite loops.
271   if (ToWidth < FromWidth && isDesirableIntType(ToWidth))
272     return true;
273 
274   // If this is a legal or desiable integer from type, and the result would be
275   // an illegal type, don't do the transformation.
276   if ((FromLegal || isDesirableIntType(FromWidth)) && !ToLegal)
277     return false;
278 
279   // Otherwise, if both are illegal, do not increase the size of the result. We
280   // do allow things like i160 -> i64, but not i64 -> i160.
281   if (!FromLegal && !ToLegal && ToWidth > FromWidth)
282     return false;
283 
284   return true;
285 }
